SELECT *
FROM attendance_record
WHERE student_id = #{studentId}
  AND attendance_date = #{attendanceDate}

SELECT COUNT(*)
FROM attendance_record
WHERE student_id = #{studentId}
  AND status = #{status, javaType=Util.AttendanceStatus, typeHandler=org.apache.ibatis.type.EnumTypeHandler}

SELECT COUNT(*) 
FROM attendance_record
WHERE student_id = #{studentId}
  AND attendance_date = #{attendanceDate}
  AND period = #{period}
